import React from 'react';
import styles from '../../styles/erpPage.module.css';

export interface VoucherListSelectionBannerProps {
  testIdPrefix: string;
  selectedCount: number;
  totalCount: number;
  selectionMode: 'page' | 'all' | null;
  pageSelectableCount: number;
  onSelectAllDatabase: () => void;
  onClear: () => void;
}

/** Banner chọn trang / chọn all DB — parity CatalogListSelectionBanner. */
export const VoucherListSelectionBanner: React.FC<VoucherListSelectionBannerProps> = ({
  testIdPrefix,
  selectedCount,
  totalCount,
  selectionMode,
  pageSelectableCount,
  onSelectAllDatabase,
  onClear,
}) => {
  if (selectedCount <= 0) return null;

  const showSelectAllDb =
    selectionMode !== 'all'
    && pageSelectableCount > 0
    && selectedCount >= pageSelectableCount
    && totalCount > selectedCount;

  return (
    <div className={styles.catalogSelectionBanner} data-testid={`${testIdPrefix}-selection-banner`}>
      {selectionMode === 'all' ? (
        <span>
          Đã chọn tất cả <strong>{totalCount}</strong> bản ghi
        </span>
      ) : (
        <span>
          Đã chọn <strong>{selectedCount}</strong>
          {pageSelectableCount > 0 ? ' trên trang này' : ''}
        </span>
      )}
      {showSelectAllDb && (
        <button
          type="button"
          className={styles.catalogSelectionLink}
          data-testid={`${testIdPrefix}-select-all-db`}
          onClick={onSelectAllDatabase}
        >
          Chọn tất cả {totalCount} bản ghi
        </button>
      )}
      <button
        type="button"
        className={styles.catalogSelectionLink}
        data-testid={`${testIdPrefix}-selection-clear`}
        onClick={onClear}
      >
        Bỏ chọn
      </button>
    </div>
  );
};
